import{_ as e,o as i,c as l,a2 as r}from"./chunks/framework.Cr-Z7ngm.js";const p=JSON.parse('{"title":"新加坡网银出金","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"withdrawal/sg-online-banking.md","filePath":"zh-CN/withdrawal/sg-online-banking.md"}'),t={name:"withdrawal/sg-online-banking.md"};function o(n,a,h,d,s,c){return i(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="新加坡网银出金" tabindex="-1">新加坡网银出金 <a class="header-anchor" href="#新加坡网银出金" aria-label="Permalink to &quot;新加坡网银出金&quot;">​</a></h1><p>新加坡账户网银和电汇出金的币种、到账时间、手续费及注意事项。</p><h2 id="操作路径" tabindex="-1">操作路径 <a class="header-anchor" href="#操作路径" aria-label="Permalink to &quot;操作路径&quot;">​</a></h2><p>长桥 App - 资产 - 全部功能 - 提取资金，选择币种和收款银行卡。</p><h2 id="支持币种" tabindex="-1">支持币种 <a class="header-anchor" href="#支持币种" aria-label="Permalink to &quot;支持币种&quot;">​</a></h2><p>新加坡元（SGD）、美元（USD）、港元（HKD）</p><h2 id="新加坡银行卡出金" tabindex="-1">新加坡银行卡出金 <a class="header-anchor" href="#新加坡银行卡出金" aria-label="Permalink to &quot;新加坡银行卡出金&quot;">​</a></h2><h3 id="到账时间" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间" aria-label="Permalink to &quot;到账时间&quot;">​</a></h3><p>预计 1-3 个交易日</p><h3 id="手续费" tabindex="-1">手续费 <a class="header-anchor" href="#手续费" aria-label="Permalink to &quot;手续费&quot;">​</a></h3><p>出金美元长桥不收费，银行方可能收费，具体以实际到账为准。</p><h2 id="非新加坡银行卡出金-电汇" tabindex="-1">非新加坡银行卡出金（电汇） <a class="header-anchor" href="#非新加坡银行卡出金-电汇" aria-label="Permalink to &quot;非新加坡银行卡出金（电汇）&quot;">​</a></h2><h3 id="到账时间-1" tabindex="-1">到账时间 <a class="header-anchor" href="#到账时间-1" aria-label="Permalink to &quot;到账时间&quot;">​</a></h3><p>预计审核 1 个工作日，出金 1-3 个工作日。因涉及跨境中转，具体到账时间以实际为准。</p><h3 id="手续费-1" tabindex="-1">手续费 <a class="header-anchor" href="#手续费-1" aria-label="Permalink to &quot;手续费&quot;">​</a></h3><p>长桥不收费。汇款银行、中间行及收款银行（尤其是 Telegraphic Transfer / SWIFT）可能收取费用，约 USD 35–60 同等值，由客户承担。</p><h2 id="出金方式限制" tabindex="-1">出金方式限制 <a class="header-anchor" href="#出金方式限制" aria-label="Permalink to &quot;出金方式限制&quot;">​</a></h2><ul><li>PayNow 不支持出金</li><li>DDA 不支持出金</li><li>Wise 首次入金后可以入金但不能通过 Wise 出金</li></ul><h2 id="同名账户要求与结算限制" tabindex="-1">同名账户要求与结算限制 <a class="header-anchor" href="#同名账户要求与结算限制" aria-label="Permalink to &quot;同名账户要求与结算限制&quot;">​</a></h2><ul><li>资金只能提取至与长桥账户同名的银行账户，不能提取到他人账户、第三方支付平台或联名银行账户</li><li>请确保银行账户支持对应的提款货币</li><li>银行账户需完成认证后方可出金，未认证的请先添加并完成认证</li><li>只能提取已结算的金额，且账户现金净余额需大于 0</li><li>汇款费用如有变更恕不另行通知，汇款银行、收款银行及中间银行产生的费用均由客户承担</li></ul>',20)])])}const b=e(t,[["render",o]]);export{p as __pageData,b as default};
